[
  {
    "name": "On Browser Home Page",
    "description": "Start the process from a fresh browser tab.",
    "triggers": ["If the current URL is chrome://new-tab-page/"],
    "actions": ["Navigate to https://www.saucedemo.com/"]
  },
  {
    "name": "On Login Page",
    "description": "Log in to Sauce Labs Demo with provided credentials.",
    "triggers": [
      "If the current URL contains saucedemo.com",
      "If an input field with placeholder 'Username' is visible"
    ],
    "actions": [
      "Type 'standard_user' into the input field with placeholder 'Username'",
      "Type 'secret_sauce' into the input field with placeholder 'Password'",
      "Click the button with text 'Login'"
    ]
  },
  {
    "name": "On Products Page",
    "description": "Add the specified products to the shopping cart.",
    "triggers": [
      "If the current URL contains saucedemo.com/inventory.html",
      "If a div with class 'inventory_list' is visible"
    ],
    "actions": [
      "Click the button with text 'Add to cart' next to 'Sauce Labs Backpack'",
      "Click the button with text 'Add to cart' next to 'Sauce Labs Bike Light'"
    ]
  },
  {
    "name": "Items Added, Open Cart",
    "description": "Navigate to the shopping cart after adding items.",
    "triggers": [
      "If the current URL contains saucedemo.com/inventory.html",
      "If a span with class 'shopping_cart_badge' shows '2'"
    ],
    "actions": ["Click the shopping cart icon"]
  },
  {
    "name": "On Cart Page",
    "description": "Proceed to checkout from the shopping cart.",
    "triggers": [
      "If the current URL contains saucedemo.com/cart.html",
      "If a button with text 'Checkout' is visible"
    ],
    "actions": ["Click the button with text 'Checkout'"]
  },
  {
    "name": "On Checkout Information Page",
    "description": "Enter customer information for the checkout process.",
    "triggers": [
      "If the current URL contains saucedemo.com/checkout-step-one.html",
      "If an input field with placeholder 'First Name' is visible"
    ],
    "actions": [
      "Type 'Test' into the input field with placeholder 'First Name'",
      "Type 'User' into the input field with placeholder 'Last Name'",
      "Type '12345' into the input field with placeholder 'Zip/Postal Code'",
      "Click the button with text 'Continue'"
    ]
  },
  {
    "name": "On Checkout Overview Page",
    "description": "Confirm the order details and complete the purchase.",
    "triggers": [
      "If the current URL contains saucedemo.com/checkout-step-two.html",
      "If a button with text 'Finish' is visible"
    ],
    "actions": ["Click the button with text 'Finish'"]
  },
  {
    "name": "Order Complete",
    "description": "Confirm that the order has been successfully placed.",
    "triggers": [
      "If the current URL contains saucedemo.com/checkout-complete.html",
      "If a h2 with text 'THANK YOU FOR YOUR ORDER' is visible"
    ],
    "actions": ["Terminate: Order successfully placed."],
    "end_state": "Order placed"
  }
]

